def sanitize_filename(filename):
    """Sanitize filename to prevent directory traversal attacks."""
    # Remove any directory components
    filename = os.path.basename(filename)
    # Remove null bytes
    filename = filename.replace('\x00', '')
    return filename


def normalize_legacy_filename(filename):
    """
    Convert modern filenames to possible legacy naming conventions.
    Supports multiple legacy formats that users may depend on.
    
    Legacy conventions supported:
    1. Spaces replaced with underscores (e.g., "my file.txt" -> "my_file.txt")
    2. Spaces replaced with hyphens (e.g., "my file.txt" -> "my-file.txt")
    3. CamelCase to snake_case (e.g., "MyFile.txt" -> "my_file.txt")
    4. Uppercase filenames (e.g., "file.txt" -> "FILE.TXT")
    5. Lowercase filenames (e.g., "FILE.TXT" -> "file.txt")
    6. URL-encoded spaces (%20) replaced with underscores or actual spaces
    7. Legacy date format prefixes (e.g., "2023-01-01_file.txt" -> "20230101_file.txt")
    8. Unicode normalization (e.g., accented chars to ASCII equivalents)
    9. Double extensions (e.g., "file.txt" -> "file.txt.bak" legacy backup convention)
    10. Legacy prefix/suffix patterns (e.g., "file.txt" -> "file_v1.txt", "file_old.txt")
    """
    candidates = []
    
    name, ext = os.path.splitext(filename)
    
    # Original filename
    candidates.append(filename)
    
    # 1. Spaces to underscores
    candidates.append(filename.replace(' ', '_'))
    
    # 2. Spaces to hyphens
    candidates.append(filename.replace(' ', '-'))
    
    # 3. Underscores to spaces
    candidates.append(filename.replace('_', ' '))
    
    # 4. Hyphens to spaces
    candidates.append(filename.replace('-', ' '))
    
    # 5. Hyphens to underscores
    candidates.append(filename.replace('-', '_'))
    
    # 6. Underscores to hyphens
    candidates.append(filename.replace('_', '-'))
    
    # 7. Lowercase version
    candidates.append(filename.lower())
    
    # 8. Uppercase version
    candidates.append(filename.upper())
    
    # 9. CamelCase to snake_case
    snake_case = re.sub(r'(?<!^)(?=[A-Z])', '_', name).lower() + ext
    candidates.append(snake_case)
    
    # 10. snake_case to CamelCase
    camel_parts = name.split('_')
    camel_case = ''.join(part.capitalize() for part in camel_parts) + ext
    candidates.append(camel_case)
    
    # 11. URL-encoded spaces decoded
    candidates.append(filename.replace('%20', ' '))
    candidates.append(filename.replace('%20', '_'))
    
    # 12. Legacy date format: YYYY-MM-DD -> YYYYMMDD
    date_pattern = re.compile(r'^(\d{4})-(\d{2})-(\d{2})[_-](.+)$')
    match = date_pattern.match(filename)
    if match:
        legacy_date = f"{match.group(1)}{match.group(2)}{match.group(3)}_{match.group(4)}"
        candidates.append(legacy_date)
    
    # 13. Reverse: YYYYMMDD -> YYYY-MM-DD
    compact_date_pattern = re.compile(r'^(\d{4})(\d{2})(\d{2})[_-](.+)$')
    match = compact_date_pattern.match(filename)
    if match:
        modern_date = f"{match.group(1)}-{match.group(2)}-{match.group(3)}_{match.group(4)}"
        candidates.append(modern_date)
    
    # 14. Unicode normalization - strip accents
    normalized = unicodedata.normalize('NFKD', filename)
    ascii_filename = normalized.encode('ascii', 'ignore').decode('ascii')
    candidates.append(ascii_filename)
    
    # 15. Legacy version suffixes
    candidates.append(f"{name}_v1{ext}")
    candidates.append(f"{name}_old{ext}")
    candidates.append(f"{name}_backup{ext}")
    candidates.append(f"{name}_legacy{ext}")
    
    # 16. Strip legacy suffixes to find the base file
    for suffix in ['_v1', '_v2', '_old', '_backup', '_legacy', '_copy', ' copy', ' (1)', '_1']:
        if name.endswith(suffix):
            base_name = name[:-len(suffix)]
            candidates.append(f"{base_name}{ext}")
    
    # 17. Handle parenthetical copy indicators: "file (1).txt" -> "file.txt"
    paren_pattern = re.compile(r'^(.+?)\s*\(\d+\)(\.[^.]+)$')
    match = paren_pattern.match(filename)
    if match:
        candidates.append(f"{match.group(1)}{match.group(2)}")
    
    # 18. Legacy double extension (e.g., file.txt.bak -> file.txt)
    if ext in ['.bak', '.old', '.orig', '.backup']:
        candidates.append(name)  # name already contains the "real" extension
    
    # 19. Try adding legacy double extensions
    candidates.append(f"{filename}.bak")
    candidates.append(f"{filename}.old")
    
    # 20. Mixed case normalization for extensions
    candidates.append(f"{name}{ext.lower()}")
    candidates.append(f"{name}{ext.upper()}")
    
    # Remove duplicates while preserving order
    seen = set()
    unique_candidates = []
    for c in candidates:
        if c not in seen and c:
            seen.add(c)
            unique_candidates.append(c)
    
    return unique_candidates


def find_file(filename):
    """
    Attempt to find a file using current and legacy naming conventions.
    Returns the actual filename on disk if found, None otherwise.
    """
    upload_folder = app.config['UPLOAD_FOLDER']
    
    # First try exact match
    filepath = os.path.join(upload_folder, filename)
    if os.path.isfile(filepath):
        return filename
    
    # Try legacy naming conventions
    candidates = normalize_legacy_filename(filename)
    for candidate in candidates:
        candidate = sanitize_filename(candidate)
        filepath = os.path.join(upload_folder, candidate)
        if os.path.isfile(filepath):
            return candidate
    
    # Case-insensitive search as last resort
    try:
        files_on_disk = os.listdir(upload_folder)
    except OSError:
        return None
    
    filename_lower = filename.lower()
    for f in files_on_disk:
        if f.lower() == filename_lower:
            return f
    
    # Try case-insensitive match against all candidates
    for candidate in candidates:
        candidate_lower = candidate.lower()
        for f in files_on_disk:
            if f.lower() == candidate_lower:
                return f
    
    return None


@app.route('/uploads/<path:filename>')
def serve_upload(filename):
    """
    Serve static files from the uploads directory with legacy filename support.
    
    Supports backward compatibility with older file naming conventions including:
    - Space/underscore/hyphen interchangeability
    - Case-insensitive matching
    - CamelCase to snake_case conversion
    - Legacy date formats
    - Legacy version suffixes
    - Unicode normalization
    - Legacy backup extensions
    """
    # Sanitize to prevent directory traversal
    filename = sanitize_filename(filename)
    
    if not filename:
        abort(400, description="Invalid filename")
    
    actual_filename = find_file(filename)
    
    if actual_filename is None:
        abort(404, description=f"File '{filename}' not found, even after trying legacy naming conventions")
    
    # If the actual filename differs from requested, log it for potential migration
    if actual_filename != filename:
        app.logger.info(
            f"Legacy filename resolution: '{filename}' -> '{actual_filename}'. "
            f"Consider updating references to use the current filename."
        )
    
    return send_from_directory(
        app.config['UPLOAD_FOLDER'],
        actual_filename,
        max_age=3600  # Cache for 1 hour
    )


@app.route('/uploads/resolve/<path:filename>')
def resolve_filename(filename):
    """
    API endpoint to check what a filename resolves to.
    Useful for debugging legacy filename issues.
    """
    filename = sanitize_filename(filename)
    
    if not filename:
        return {"error": "Invalid filename"}, 400
    
    actual_filename = find_file(filename)
    candidates = normalize_legacy_filename(filename)
    
    upload_folder = app.config['UPLOAD_FOLDER']
    existing_candidates = [
        c for c in candidates
        if os.path.isfile(os.path.join(upload_folder, sanitize_filename(c)))
    ]
    
    return {
        "requested": filename,
        "resolved": actual_filename,
        "found": actual_filename is not None,
        "candidates_checked": len(candidates),
        "existing_matches": existing_candidates
    }


@app.route('/uploads/')
def list_uploads():
    """List all files in the uploads directory."""
    upload_folder = app.config['UPLOAD_FOLDER']
    try:
        files = sorted(os.listdir(upload_folder))
        files = [f for f in files if os.path.isfile(os.path.join(upload_folder, f))]
    except OSError:
        files = []
    
    return {
        "upload_directory": upload_folder,
        "file_count": len(files),
        "files": files
    }


